import{_ as a,o as r,c as t,a1 as o}from"./chunks/framework.BwbI10pK.js";const f=JSON.parse('{"title":"框架与生态","description":"","frontmatter":{},"headers":[],"relativePath":"frameworks/index.md","filePath":"frameworks/index.md"}'),i={name:"frameworks/index.md"};function l(n,e,s,u,c,d){return r(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="框架与生态" tabindex="-1">框架与生态 <a class="header-anchor" href="#框架与生态" aria-label="Permalink to &quot;框架与生态&quot;">​</a></h1><blockquote><p>副标题：看透 React Fiber、Vue 3 响应式与状态管理抽象背后的工程取舍</p></blockquote><h2 id="模块定位" tabindex="-1">模块定位 <a class="header-anchor" href="#模块定位" aria-label="Permalink to &quot;模块定位&quot;">​</a></h2><p>现代前端框架把&quot;如何更新 DOM&quot;这件事抽象得越来越彻底，但抽象不是免费的。React Fiber 的链式可中断渲染、Vue 3 的 Proxy 响应式、Zustand 的原子化状态，每一种方案背后都是对&quot;调度、依赖追踪、性能与开发体验&quot;的不同取舍。</p><p>本模块不只讲&quot;怎么用框架&quot;，而是拆开框架的内部机制，让你理解它为什么这样设计、在什么场景下会有性能瓶颈、什么情况下应该绕过抽象直接操作底层。</p><h2 id="核心主题" tabindex="-1">核心主题 <a class="header-anchor" href="#核心主题" aria-label="Permalink to &quot;核心主题&quot;">​</a></h2><ul><li><strong>调度机制</strong>：React Fiber 链表结构、时间切片、可中断渲染与并发模式</li><li><strong>响应式系统</strong>：Vue 3 Proxy 依赖收集、Effect 调度、ref / reactive / computed 的实现差异</li><li><strong>状态管理</strong>：Flux 单向流、Redux 中间件、Zustand 原子化、Recoil 派生状态的设计演进</li><li><strong>工程取舍</strong>：运行时 vs 编译时、细粒度更新 vs 虚拟 DOM diff、单 store vs 原子的权衡</li></ul><h2 id="文章导览" tabindex="-1">文章导览 <a class="header-anchor" href="#文章导览" aria-label="Permalink to &quot;文章导览&quot;">​</a></h2><ul><li><a href="/frameworks/react-fiber">React Fiber 架构：从栈调度到链式可中断渲染</a> — Fiber 节点结构、Scheduler、Lane 优先级模型</li><li><a href="/frameworks/vue3-reactivity">Vue 3 响应式系统：Proxy 与依赖收集的完整实现</a> — 从 Proxy trap 到 Effect 调度的完整链路</li><li><a href="/frameworks/state-management">现代状态管理演进：从 Flux 到 Zustand 的设计哲学</a> — 单向流、不可变性、原子化的取舍脉络</li></ul><h2 id="适用读者" tabindex="-1">适用读者 <a class="header-anchor" href="#适用读者" aria-label="Permalink to &quot;适用读者&quot;">​</a></h2><ul><li>中高级前端工程师，希望理解框架内部机制而非只会用 API</li><li>前端架构师，需要在技术选型时评估不同框架的性能边界</li><li>框架源码贡献者，需要建立调度、响应式、状态管理的统一视角</li></ul>',11)])])}const m=a(i,[["render",l]]);export{f as __pageData,m as default};
